// Package capi contains the C struct layouts for CEF types.
// Code in this package is generated by cefgen and should not be edited manually.
package capi

// ---------------------------------------------------------------------------
// Hand-written foundational types not generated from headers.
// ---------------------------------------------------------------------------

// CEFStringT mirrors cef_string_t (cef_string_utf16_t on Linux/Mac/Windows).
type CEFStringT struct {
	Str    *uint16
	Length uintptr
	Dtor   uintptr
}

// CEFColorT mirrors cef_color_t (typedef uint32_t).
type CEFColorT = uint32

// CEFBasetimeT mirrors cef_basetime_t (wraps int64).
type CEFBasetimeT struct {
	Val int64
}

// CEFWindowHandleT mirrors cef_window_handle_t (unsigned long on Linux).
type CEFWindowHandleT = uint64
